import {
  ReloadOutlined,
  TeamOutlined,
  UserDeleteOutlined,
  UserOutlined,
} from "@ant-design/icons"
import { Line, Pie } from "@ant-design/plots"
import {
  Button,
  Card,
  Col,
  Row,
  Select,
  Space,
  Statistic,
  Tooltip,
  Typography,
} from "antd"
import dayjs from "dayjs"
import _ from "lodash"
import { useEffect, useMemo, useState } from "react"
import { useSelector } from "react-redux"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import { GUIDE_EMPTY, GUIDE_ONE, SYSTEM_KEY } from "src/constants/constants"
import { removeDiacritics } from "src/lib/stringsUtils"
import { getListComboByKey } from "src/lib/utils"
import AssociationService from "src/services/AssociationService"
import MembershipTypeService from "src/services/MembershipTypeService"
import MemberStatisticsService from "src/services/MemberStatisticsService"
import { ColorPrimary } from "src/theme/GlobalThemeConfig"

const { Option } = Select
const { Text } = Typography

const MemberStatistics = () => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [loading, setLoading] = useState(false)
  const [treeLoading, setTreeLoading] = useState(false)
  const [packageList, setPackageList] = useState([])
  const [treeData, setTreeData] = useState({ tree: [], dataList: [] })
  const [selectedNode, setSelectedNode] = useState(null)

  const [filters, setFilters] = useState({
    selectedMonth: 3,
    memberType: "",
    selectedDate: dayjs(),
    quarter: "",
    packageId: "",
    associationId: GUIDE_ONE,
  })

  const [data, setData] = useState({
    memberCount: null,
    memberComposition: [],
    memberStatistics: [],
  })

  const sort = items => {
    return _.orderBy(items, ["Level", "SortOrder"], ["asc", "asc"])
  }

  const nest = (items, id, link) => {
    return items
      ?.filter(item => item[link] === id)
      .map(item => ({
        ...item,
        title: item.title,
        key: item.key,
        value: item.key,
        children: nest(items, item?.key, link),
      }))
  }

  // lấy dữ liệu Tree
  const getListAssoc = async () => {
    try {
      setTreeLoading(true)
      const res = await AssociationService.getAssociationNameList({
        AssociationID: GUIDE_EMPTY,
        AssociationName: "",
      })

      if (res?.isError) return

      const dataList = sort(
        res?.Object?.map(item => ({
          ...item,
          key: item?.AssociationID,
          title: item?.AssociationName || "",
          removeDiacriticsTitle: removeDiacritics(
            (item?.AssociationName || "").toLowerCase(),
          ),
        })) || [],
      )

      const tree = nest(dataList, GUIDE_EMPTY, "ParentID")
      setTreeData({ tree: tree, dataList: dataList })
    } catch (error) {
      console.error("Lỗi khi tải danh sách hiệp hội:", error)
    } finally {
      setTreeLoading(false)
    }
  }

  const fetchPackageList = async () => {
    try {
      const requestBody = {
        PageSize: 999,
        CurrentPage: 1,
        TextSearch: "",
        Status: 0,
        MemberType: 0,
      }

      const response = await MembershipTypeService.getListPackage(requestBody)
      if (response?.isOk && response?.StatusCode === 200) {
        setPackageList(response.Object?.ListPackage || [])
      }
    } catch (error) {
      console.error("Lỗi khi tải danh sách gói:", error)
    }
  }

  const fetchMemberCount = async (months, associationId) => {
    try {
      const validMonths = parseInt(months) || 3
      const response = await MemberStatisticsService.getMemberCount(
        validMonths,
        associationId && associationId !== GUIDE_EMPTY
          ? associationId
          : undefined,
      )

      if (response?.isOk && response?.StatusCode === 200) {
        setData(prev => ({ ...prev, memberCount: response.Object }))
      }
    } catch (error) {
      console.error("Lỗi khi tải thống kê số lượng thành viên:", error)
    }
  }

  const fetchMemberComposition = async (memberType, associationId) => {
    try {
      const params = {}
      if (memberType) params.memberType = Number(memberType)
      if (associationId && associationId !== GUIDE_EMPTY)
        params.associationId = associationId

      const response = await MemberStatisticsService.getPackageUserCount(
        Object.keys(params).length > 0 ? params : null,
      )
      setData(prev => ({ ...prev, memberComposition: response.Object || [] }))
    } catch (error) {
      console.error("Lỗi khi tải cơ cấu thành viên:", error)
    }
  }

  const fetchMemberStatistics = async (
    selectedDate,
    quarter,
    packageId,
    associationId,
  ) => {
    try {
      let quarterValue = null
      if (quarter && quarter !== "") {
        quarterValue = parseInt(quarter)
      }

      let packageIdValue = null
      if (packageId && packageId !== "") {
        packageIdValue = packageId
      }

      const yearValue = selectedDate
        ? selectedDate.year()
        : new Date().getFullYear()

      const response = await MemberStatisticsService.getMemberStatistics(
        yearValue,
        quarterValue,
        packageIdValue,
        associationId && associationId !== GUIDE_EMPTY
          ? associationId
          : undefined,
      )

      setData(prev => ({ ...prev, memberStatistics: response.Object || [] }))
    } catch (error) {
      console.error("Lỗi khi tải thống kê biến động thành viên:", error)
    }
  }

  const pieData = useMemo(() => {
    if (!data.memberComposition.length) return []

    const total = data.memberComposition.reduce(
      (sum, item) => sum + (item.UserCount || 0),
      0,
    )
    return data.memberComposition.map(item => ({
      type: item.PackageName || "Không xác định",
      value: item.UserCount || 0,
      percentage: total > 0 ? ((item.UserCount / total) * 100).toFixed(1) : "0",
    }))
  }, [data.memberComposition])

  const lineData = useMemo(() => {
    if (!data.memberStatistics.length) return []

    return data.memberStatistics.flatMap(item => [
      {
        month: `Tháng ${item.Month}`,
        value: item.IndividualCount || 0,
        type: "Cá Nhân",
      },
      {
        month: `Tháng ${item.Month}`,
        value: item.OrganizationCount || 0,
        type: "Doanh nghiệp",
      },
    ])
  }, [data.memberStatistics])

  const pieConfig = {
    data: pieData,
    angleField: "value",
    colorField: "type",
    innerRadius: 0.6,
    color: [
      "#52c41a",
      "#ff7875",
      "#597ef7",
      "#ffc53d",
      "#73d13d",
      "#ff9c6e",
      "#b37feb",
    ],
    label: {
      text: "value",
      style: {
        fontWeight: "bold",
        fontSize: 12,
      },
    },
    legend: {
      color: {
        title: false,
        position: "right",
        rowPadding: 5,
      },
    },
    statistic: {
      title: {
        style: { fontSize: "14px", color: "#8c8c8c" },
        content: "Tổng cộng",
      },
      content: {
        style: { fontSize: "24px", fontWeight: "bold", color: "#1890ff" },
        content: pieData.reduce((sum, item) => sum + item.value, 0).toString(),
      },
    },
  }

  const lineConfig = {
    data: lineData,
    xField: "month",
    yField: "value",
    colorField: "type",
    color: datum => (datum.type === "Cá Nhân" ? "#1890ff" : ColorPrimary),
    yAxis: { min: 0 },
    smooth: true,
    point: {
      size: 5,
      shape: "circle",
    },
    animation: {
      appear: {
        animation: "path-in",
        duration: 2000,
      },
    },
  }

  const refreshData = async () => {
    try {
      setLoading(true)
      await Promise.all([
        fetchMemberCount(filters.selectedMonth, filters.associationId),
        fetchMemberComposition(filters.memberType, filters.associationId),
        fetchMemberStatistics(
          filters.selectedDate,
          filters.quarter,
          filters.packageId,
          filters.associationId,
        ),
      ])
    } finally {
      setLoading(false)
    }
  }

  const getInitialData = async () => {
    try {
      setLoading(true)
      await Promise.all([
        getListAssoc(),
        fetchPackageList(),
        fetchMemberCount(filters.selectedMonth, filters.associationId),
        fetchMemberComposition(filters.memberType, filters.associationId),
        fetchMemberStatistics(
          filters.selectedDate,
          filters.quarter,
          filters.packageId,
          filters.associationId,
        ),
      ])
    } finally {
      setLoading(false)
    }
  }

  const handleNodeSelect = node => {
    setSelectedNode(node)
    setFilters(prev => ({ ...prev, associationId: node?.key || GUIDE_EMPTY }))
  }
  useEffect(() => {
    getInitialData()
  }, [])

  useEffect(() => {
    if (loading || treeLoading) return

    refreshData()
  }, [
    filters.selectedMonth,
    filters.memberType,
    filters.selectedDate,
    filters.quarter,
    filters.packageId,
    filters.associationId,
  ])

  return (
    <SpinCustom spinning={loading || treeLoading}>
      <div style={{ minHeight: "100vh" }}>
        <Row gutter={[16, 16]} style={{ height: "100%" }}>
          {/* Right side - Statistics */}
          <Col span={24}>
            {/* Header */}
            <Row gutter={[16, 16]} className="mb-16" align="bottom">
              <Col flex="auto">
                <div className="title-type-1" style={{ paddingBottom: 4 }}>
                  Thống kê Hội Viên
                </div>
              </Col>

              {/* Select và nút làm mới bên phải */}
              <Col>
                <Space>
                  <SelectCustom
                    style={{ width: 160 }}
                    value={filters.selectedMonth}
                    onChange={selectedMonth =>
                      setFilters(prev => ({ ...prev, selectedMonth }))
                    }
                    placeholder="Chọn tháng"
                  >
                    {getListComboByKey(
                      SYSTEM_KEY?.MONTH_CATE,
                      listSystemKey,
                    )?.map(i => (
                      <Option key={i.CodeValue} value={i.CodeValue}>
                        {i.Description}
                      </Option>
                    ))}
                  </SelectCustom>

                  <Button
                    type="primary"
                    icon={<ReloadOutlined />}
                    onClick={refreshData}
                    loading={loading}
                  >
                    Làm mới
                  </Button>
                </Space>
              </Col>
            </Row>

            {/* First Row: 3 Statistics Cards + Pie Chart */}
            <Row gutter={[16, 16]} className="mb-24">
              {/* Pie Chart */}
              <Col xs={24} lg={12} style={{ height: "100%" }}>
                <Card
                  title={
                    <Tooltip title="Cơ cấu số Hội Viên">
                      <span>Cơ cấu số Hội Viên</span>
                    </Tooltip>
                  }
                  style={{ height: "90%" }}
                  extra={
                    <SelectCustom
                      style={{ width: 150 }}
                      value={filters.memberType}
                      onChange={memberType =>
                        setFilters(prev => ({ ...prev, memberType }))
                      }
                      placeholder="Loại hội viên"
                    >
                      <Option value="">Tất cả</Option>
                      {getListComboByKey(
                        SYSTEM_KEY?.MEMBER_TYPE,
                        listSystemKey,
                      )?.map(i => (
                        <Option key={i.CodeValue} value={i.CodeValue}>
                          {i.Description}
                        </Option>
                      ))}
                    </SelectCustom>
                  }
                >
                  <div style={{ height: "285px" }}>
                    {pieData.length > 0 ? (
                      <Pie {...pieConfig} />
                    ) : (
                      <div
                        style={{
                          height: "285px",
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          color: "#999",
                        }}
                      >
                        Không có dữ liệu
                      </div>
                    )}
                  </div>
                </Card>
              </Col>

              {/* 3 Statistics Cards */}
              <Col xs={24} lg={12} style={{ height: "100%" }}>
                <Row
                  gutter={[16, 16]}
                  style={{
                    height: "100%",
                    display: "flex",
                    flexDirection: "column",
                  }}
                >
                  <Col span={24} style={{ flex: 1 }}>
                    <Card style={{ height: "100%" }}>
                      <Statistic
                        title={
                          <span style={{ color: "#5b8ff9" }}>
                            Tổng số Hội Viên
                          </span>
                        }
                        value={data.memberCount?.TotalMemberCount || 0}
                        prefix={<UserOutlined style={{ color: "#5b8ff9" }} />}
                        valueStyle={{
                          color: "#5b8ff9",
                          fontSize: "28px",
                          fontWeight: "bold",
                        }}
                      />
                    </Card>
                  </Col>

                  <Col span={24} style={{ flex: 1 }}>
                    <Card style={{ height: "100%" }}>
                      <Statistic
                        title={
                          <span style={{ color: "#52c41a" }}>Hội Viên Mới</span>
                        }
                        value={data.memberCount?.NewMemberCount || 0}
                        prefix={<TeamOutlined style={{ color: "#52c41a" }} />}
                        valueStyle={{
                          color: "#52c41a",
                          fontSize: "28px",
                          fontWeight: "bold",
                        }}
                      />
                    </Card>
                  </Col>

                  <Col span={24} style={{ flex: 1 }}>
                    <Card style={{ height: "100%" }}>
                      <Statistic
                        title={
                          <span style={{ color: "#ff4d4f" }}>
                            Hội Viên Rời Khỏi
                          </span>
                        }
                        value={data.memberCount?.LeaveMemberCount || 0}
                        prefix={
                          <UserDeleteOutlined style={{ color: "#ff4d4f" }} />
                        }
                        valueStyle={{
                          color: "#ff4d4f",
                          fontSize: "28px",
                          fontWeight: "bold",
                        }}
                      />
                    </Card>
                  </Col>
                </Row>
              </Col>
            </Row>

            {/* Second Row: Line Chart */}
            <Row gutter={[16, 16]}>
              <Col span={24}>
                <Card
                  title={
                    <Tooltip title="Biến động Hội Viên">
                      <span>Biến động Hội Viên</span>
                    </Tooltip>
                  }
                  style={{ height: "100%" }}
                  extra={
                    <Space wrap>
                      <DatePickerCustom
                        picker="year"
                        value={filters.selectedDate}
                        onChange={date =>
                          setFilters(prev => ({ ...prev, selectedDate: date }))
                        }
                        placeholder="Chọn năm"
                        style={{ width: 100 }}
                        allowClear={false}
                      />

                      <SelectCustom
                        style={{ width: 100 }}
                        value={filters.quarter}
                        onChange={quarter =>
                          setFilters(prev => ({ ...prev, quarter }))
                        }
                        placeholder="Quý"
                      >
                        <Option value="">Tất cả</Option>
                        {getListComboByKey(
                          SYSTEM_KEY?.QUARTER,
                          listSystemKey,
                        )?.map(i => (
                          <Option key={i.CodeValue} value={i.CodeValue}>
                            {i.Description}
                          </Option>
                        ))}
                      </SelectCustom>

                      <SelectCustom
                        style={{ width: 140 }}
                        value={filters.packageId}
                        onChange={packageId =>
                          setFilters(prev => ({ ...prev, packageId }))
                        }
                        placeholder="Gói hội viên"
                      >
                        <Option value="">Tất cả</Option>
                        {packageList?.map(pkg => (
                          <Option key={pkg.PackageID} value={pkg.PackageID}>
                            {pkg.PackageName}
                          </Option>
                        ))}
                      </SelectCustom>
                    </Space>
                  }
                >
                  <div style={{ height: "450px" }}>
                    {lineData.length > 0 ? (
                      <Line {...lineConfig} />
                    ) : (
                      <div
                        style={{
                          height: "100%",
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          color: "#999",
                        }}
                      >
                        Không có dữ liệu
                      </div>
                    )}
                  </div>
                </Card>
              </Col>
            </Row>
          </Col>
        </Row>
      </div>
    </SpinCustom>
  )
}

export default MemberStatistics
